49	static void error_on_dpi_function(AST::AstNode *node)
50	{
51	    if (node->type == AST::AST_DPI_FUNCTION)
52	        err_at_loc(node->location, "Found DPI function %s.\n", node->str);
53	    for (auto& child : node->children)
54	        error_on_dpi_function(child.get());
55	}
