57	static void add_package_types(dict<std::string, AST::AstNode *> &user_types, std::vector<std::unique_ptr<AST::AstNode>> &package_list)
58	{
59		// prime the parser's user type lookup table with the package qualified names
60		// of typedefed names in the packages seen so far.
61		for (const auto &pkg : package_list) {
62			log_assert(pkg->type==AST::AST_PACKAGE);
63			for (const auto &node: pkg->children) {
64				if (node->type == AST::AST_TYPEDEF) {
65					std::string s = pkg->str + "::" + node->str.substr(1);
66					user_types[s] = node.get();
67				}
68			}
69		}
70	}
